"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[90829],{86591(e,t,n){n.r(t),n.d(t,{assets:()=>d,contentTitle:()=>r,default:()=>l,frontMatter:()=>o,metadata:()=>i,toc:()=>c});let i=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 7 Statement of Cash Flows/demand-deposits-with-restrictions-on-d9379cfc70","title":"Demand Deposits with Restrictions on Use arising from a Contract with a Third Party (IAS 7)","description":"April 2022","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 7 Statement of Cash Flows/Demand Deposits with Restrictions on Use arising from a Contract with a Third Party (IAS 7).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 7 Statement of Cash Flows","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/demand-deposits-with-restrictions-on-d9379cfc70","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/demand-deposits-with-restrictions-on-d9379cfc70","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"demand-deposits-with-restrictions-on-d9379cfc70","title":"Demand Deposits with Restrictions on Use arising from a Contract with a Third Party (IAS 7)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/demand-deposits-with-restrictions-on-d9379cfc70","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Subsequent Expenditure on Biological Assets (IAS 41)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-41-agriculture-c896891f3d/subsequent-expenditure-on-biological-9da09e016f"},"next":{"title":"Disclosure of Changes in Liabilities Arising from Financing Activities (IAS 7)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/disclosure-of-changes-in-liabilities-8c638cacbf"}}');var a=n(74848),s=n(28453);let o={id:"demand-deposits-with-restrictions-on-d9379cfc70",title:"Demand Deposits with Restrictions on Use arising from a Contract with a Third Party (IAS 7)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/demand-deposits-with-restrictions-on-d9379cfc70",sidebar_position:1},r="Demand Deposits with Restrictions on Use arising from a Contract with a Third Party (IAS 7)",d={},c=[{value:"Cash and cash equivalents in the statement of cash flows",id:"cash-and-cash-equivalents-in-the-statement-of-cash-flows",level:2},{value:"Presentation in the statement of financial position",id:"presentation-in-the-statement-of-financial-position",level:2},{value:"Disclosures",id:"disclosures",level:2}];function h(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"demand-deposits-with-restrictions-on-use-arising-from-a-contract-with-a-third-party-ias-7",children:"Demand Deposits with Restrictions on Use arising from a Contract with a Third Party (IAS 7)"})}),"\n",(0,a.jsx)(t.p,{children:"April 2022"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about whether an entity includes a demand deposit as a component of cash and cash equivalents in its statements of cash flows and financial position when the demand deposit is subject to contractual restrictions on use agreed with a third party. In the fact pattern described in the request, the entity:"}),"\n",(0,a.jsx)(t.p,{children:"a. holds a demand deposit whose terms and conditions do not prevent the entity from accessing the amounts held in it (that is, were the entity to request any amount from the deposit, it would receive that amount on demand).\nb. has a contractual obligation with a third party to keep a specified amount of cash in that separate demand deposit and to use the cash only for specified purposes. If the entity were to use the amounts held in the demand deposit for purposes other than those agreed with the third party, the entity would be in breach of its contractual obligation."}),"\n",(0,a.jsx)(t.h2,{id:"cash-and-cash-equivalents-in-the-statement-of-cash-flows",children:"Cash and cash equivalents in the statement of cash flows"}),"\n",(0,a.jsx)(t.p,{children:"The Committee noted that the question in the request is about whether the demand deposit meets the definition of \u2018cash\u2019 in IAS 7."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 6 of IAS 7 defines \u2018cash\u2019 by stating that it \u2018comprises cash on hand and demand deposits.\u2019 IAS 7 includes no requirements on whether an item qualifies as cash beyond the definition itself."}),"\n",(0,a.jsx)(t.p,{children:"IAS 7 and IAS 1 Presentation of Financial Statements indicate that amounts included in cash and cash equivalents may be subject to restrictions, namely:"}),"\n",(0,a.jsx)(t.p,{children:"a. paragraph 48 of IAS 7 requires an entity to disclose information about \u2018significant cash and cash equivalent balances held by the entity that are not available for use by the group\u2019; and\nb. paragraph 66(d) of IAS 1 requires an entity to classify as current an asset that is \u2018cash or a cash equivalent (as defined in IAS 7) unless the asset is restricted from being exchanged or used to settle a liability for at least twelve months after the reporting period\u2019."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that restrictions on the use of a demand deposit arising from a contract with a third party do not result in the deposit no longer being cash, unless those restrictions change the nature of the deposit in a way that it would no longer meet the definition of cash in IAS 7. In the fact pattern described in the request, the contractual restrictions on the use of the amounts held in the demand deposit do not change the nature of the deposit\u2014the entity can access those amounts on demand. Therefore, the Committee concluded that the entity includes the demand deposit as a component of \u2018cash and cash equivalents\u2019 in its statement of cash flows."}),"\n",(0,a.jsx)(t.h2,{id:"presentation-in-the-statement-of-financial-position",children:"Presentation in the statement of financial position"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 54(i) of IAS 1 requires an entity to include a line item in its statement of financial position that presents the amount of \u2018cash and cash equivalents\u2019. Paragraph 55 of IAS 1 states \u2018an entity shall present additional line items (including by disaggregating the line items listed in paragraph 54) \u2026 in the statement of financial position when such presentation is relevant to an understanding of the entity\u2019s financial position\u2019."}),"\n",(0,a.jsx)(t.p,{children:"Therefore, the Committee concluded that, in the fact pattern described in the request, the entity presents the demand deposit as cash and cash equivalents in its statement of financial position. When relevant to an understanding of its financial position, the entity would disaggregate the \u2018cash and cash equivalents\u2019 line item and present the demand deposit separately in an additional line item."}),"\n",(0,a.jsx)(t.p,{children:"An entity that presents assets as current or non-current would classify the demand deposit as current applying paragraph 66(d) of IAS 1, unless the demand deposit is \u2018restricted from being exchanged or used to settle a liability for at least twelve months after the reporting period\u2019."}),"\n",(0,a.jsx)(t.h2,{id:"disclosures",children:"Disclosures"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 45 of IAS 7 states that \u2018an entity shall disclose the components of cash and cash equivalents\u2026\u2019. Applying this requirement, in the fact pattern described in the request, the entity discloses the demand deposit as a component of cash and cash equivalents. The entity also considers whether to disclose additional information:"}),"\n",(0,a.jsx)(t.p,{children:"a. in the context of the requirements in IFRS 7 Financial Instruments: Disclosures about liquidity risk arising from financial instruments and how an entity manages that risk; and\nb. if the information it provides in applying the disclosure requirements in IAS 7 and IFRS 7 is insufficient to enable users of financial statements to understand the impact of the restrictions on the entity\u2019s financial position (paragraph 31 of IAS 1)."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS Accounting Standards provide an adequate basis for an entity to determine whether to include demand deposits subject to contractual restrictions on use agreed with a third party as a component of cash and cash equivalents in its statements of cash flows and financial position. Consequently, the Committee decided not to add a standard-setting project to the work plan."})]})}function l(e={}){let{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(h,{...e})}):h(e)}},28453(e,t,n){n.d(t,{R:()=>o,x:()=>r});var i=n(96540);let a={},s=i.createContext(a);function o(e){let t=i.useContext(s);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),i.createElement(s.Provider,{value:t},e.children)}}}]);